golden_rtl:
module mod3_counter(input logic clk, input logic rst_n, output logic [1:0] count);
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) count <= 2'd0;
    else if (count == 2'd2) count <= 2'd0;
    else count <= count + 2'd1;
  end
endmodule

mutant_rtls:
module mod3_counter(input logic clk, input logic rst_n, output logic [1:0] count);
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) count <= 2'd1;
    else if (count == 2'd2) count <= 2'd0;
    else count <= count + 2'd1;
  end
endmodule
module mod3_counter(input logic clk, input logic rst_n, output logic [1:0] count);
  always_ff @(posedge clk or negedge rst_n) begin
