reference_tb:
`timescale 1ns/1ps
module tb;
  logic clk, rst_n;
  logic [1:0] count;

  mod3_counter dut(.clk(clk), .rst_n(rst_n), .count(count));

  always #5 clk = ~clk;

  task check_count(input [1:0] exp_count);
    begin
      @(posedge clk); #1;
      if (count !== exp_count) begin
        $display("FAIL expected=%0d got=%0d", exp_count, count);
        $fatal(1);
      end
    end
  endtask

  initial begin
    clk = 0; rst_n = 0;
    check_count(2'd0);
    rst_n = 1;
    check_count(2'd1);
    check_count(2'd2);
    check_count(2'd0);
    check_count(2'd1);
    check_count(2'd2);
    $display("PASS");
    $finish;
  end
endmodule
